// MARK: - Example Usage (e.g., in a ViewController or a dedicated service)

import UIKit

// Define some example models for decoding responses
struct CloudAPIResponse: Decodable {
    let message: String
    let status: String
}

struct IoTDeviceStatus: Decodable {
    let deviceId: String
    let temperature: Double
    let humidity: Double
    let online: Bool
}

struct IoTDeviceCommand: Encodable {
    let command: String
    let value: Int
}

class ViewController: UIViewController {

    let networkClient = NetworkClient()

    override func viewDidLoad() {
        super.viewDidLoad()
        
        // Example: Fetch data from Cloud API (HTTPS)
        fetchCloudData()

        // Example: Fetch data from Local IoT Device (HTTP)
        fetchLocalIoTStatus()

        // Example: Send command to Local IoT Device (HTTP POST)
        sendLocalIoTCommand()
    }

    func fetchCloudData() {
        guard let url = URL(string: "https://api.example.com/status") else {
            print("Invalid Cloud API URL")
            return
        }

        networkClient.get(url: url) { (result: Result<CloudAPIResponse, NetworkClient.NetworkError>) in
            DispatchQueue.main.async {
                switch result {
                case .success(let response):
                    print("Cloud API Success: \(response.message) - \(response.status)")
                case .failure(let error):
                    print("Cloud API Error: \(error.localizedDescription)")
                }
            }
        }
    }

    func fetchLocalIoTStatus() {
        // Example IP address for a local device
        guard let url = URL(string: "http://192.168.1.100/status") else {
            print("Invalid Local IoT Device URL")
            return
        }

        networkClient.get(url: url) { (result: Result<IoTDeviceStatus, NetworkClient.NetworkError>) in
            DispatchQueue.main.async {
                switch result {
                case .success(let status):
                    print("IoT Device Status Success: Device \(status.deviceId) - Temp: \(status.temperature)°C")
                case .failure(let error):
                    print("IoT Device Status Error: \(error.localizedDescription)")
                    // If it's a server error, you might want to inspect the raw data
                    if case .serverError(_, let data) = error, let data = data, let str = String(data: data, encoding: .utf8) {
                        print("Raw IoT error data: \(str)")
                    }
                }
            }
        }
    }

    func sendLocalIoTCommand() {
        guard let url = URL(string: "http://192.168.1.100/command") else {
            print("Invalid Local IoT Command URL")
            return
        }

        let command = IoTDeviceCommand(command: "turnOn", value: 1)

        networkClient.post(url: url, body: command) { (result: Result<CloudAPIResponse, NetworkClient.NetworkError>) in
            // Assuming the IoT device returns a similar confirmation structure
            DispatchQueue.main.async {
                switch result {
                case .success(let response):
                    print("IoT Command Success: \(response.message)")
                case .failure(let error):
                    print("IoT Command Error: \(error.localizedDescription)")
                }
            }
        }
    }
}

